import{_ as a,H as t,f as s,i}from"./chunks/framework.DbTCwA-u.js";const c=JSON.parse('{"title":"Holographic Pets","description":"How to configure pet nametags in pets.yml.","frontmatter":{"title":"Holographic Pets","description":"How to configure pet nametags in pets.yml."},"headers":[],"relativePath":"config/pets.md","filePath":"config/pets.md"}'),n={name:"config/pets.md"};function l(o,e,h,r,p,g){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="holographic-pets-pets-yml" tabindex="-1">Holographic Pets (pets.yml) <a class="header-anchor" href="#holographic-pets-pets-yml" aria-label="Permalink to &quot;Holographic Pets (pets.yml)&quot;">​</a></h1><p>The pet system is one of the most innovative features of EligiusNametag. With it, any wolf, parrot, or cat tamed by a player will receive a floating holographic nametag that smoothly follows the pet.</p><h3 id="base-configuration" tabindex="-1">Base Configuration <a class="header-anchor" href="#base-configuration" aria-label="Permalink to &quot;Base Configuration&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  show_unnamed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li>If <code>show_unnamed</code> is <code>true</code>, even a generic tamed wolf will have a text hologram.</li><li>If set to <code>false</code>, only pets that the player renames using an <strong>Anvil</strong> (vanilla Name Tag) will activate the holographic system to preserve a more Vanilla style on the general server.</li></ul><h3 id="line-design" tabindex="-1">Line Design <a class="header-anchor" href="#line-design" aria-label="Permalink to &quot;Line Design&quot;">​</a></h3><p>Use <code>&lt;DISPLAYNAME&gt;</code> to show the name the player gave it in the anvil, and <code>&lt;PLAYER&gt;</code> to quote the owner.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  default_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gray&gt;&lt;PLAYER&gt;&#39;s Pet&lt;/gray&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;DISPLAYNAME&gt;&lt;/white&gt;&quot;</span></span></code></pre></div><h3 id="🐾-the-biggest-secret" tabindex="-1">🐾 The Biggest Secret! <a class="header-anchor" href="#🐾-the-biggest-secret" aria-label="Permalink to &quot;🐾 The Biggest Secret!&quot;">​</a></h3><p>Pets <strong>inherit</strong> their owner&#39;s Vault rank design. This means that if a cat&#39;s owner has the &quot;Admin&quot; rank in <code>players.yml</code>, and the Admin rank has red text and a fire icon, <strong>the cat will also show the red text and fire icon</strong> in its group variable (if you configure it this way by crossing PAPI variables or LuckPerms permissions at the <code>&lt;PLAYER&gt;</code> node level).</p>`,10)])])}const k=a(n,[["render",l]]);export{c as __pageData,k as default};
